SELECT AVG(total_population) AS average_population
FROM demographic_data
WHERE county_id = 1;

SELECT SUM(total_population) AS total_population
FROM demographic_trends
WHERE year = 2018;

SELECT population_density
FROM counties
WHERE county_id = 1;

SELECT COUNT(county_id) AS county_count
FROM counties
WHERE state = 'Arkansas';

SELECT AVG(total_population) AS average_population
FROM demographic_data
WHERE collection_year = 2018;
